import{i as n,r as s,o as a,f as e,g as l,w as p,F as t,h as o}from"./vendor.e22515e8.js";const r=[{name:"nuxt",value:'<h2>nuxt JS</h2>\n<h3>一个请求到服务端后发生的</h3>\n<p>执行顺序 1-1-2-3</p>\n<p>koa里面</p>\n<ol>\n<li>server koa middleware</li>\n</ol>\n<p>nuxt.render里面</p>\n<ol>\n<li>connect middleware</li>\n<li>load and execute vue plugins</li>\n<li>load and execute vue router middleware</li>\n</ol>\n<p><a href="https://nuxtjs.org/guide#schema">官方链接</a></p>\n<h2>Node 缓存方案对比</h2>\n<p>Redis vs Simple Memory</p>\n<h3>[Redis]:</h3>\n<p>pros:</p>\n<ol>\n<li>外部缓存，保证数据一致性</li>\n<li>支持的数据类型足够多</li>\n</ol>\n<p>cons:</p>\n<ol>\n<li>复杂</li>\n<li>异步</li>\n<li>重启的时候不会清空缓存（会导致预期的改动效果没法立即展现在用户面前），需要做手动处理</li>\n<li>整体的运行配置会比较多</li>\n<li>不过存储不了 Promise</li>\n</ol>\n<h3>[Simple Memory]:</h3>\n<p>props:</p>\n<ol>\n<li>简单</li>\n<li>同步</li>\n<li>重启后数据重置\n能存储 Promise 等 Node自带对象结构，增加了灵活性（现阶段已经使用在axios的接口adapter promise缓存上）</li>\n</ol>\n<p>cons:</p>\n<ol>\n<li>分布式数据不一致</li>\n</ol>\n<h3>Redis 本地可视化测试</h3>\n<pre><code class="language-bash">npm install -g redis-commander\nredis-commander\n</code></pre>\n<h3>结论：</h3>\n<p>目前先使用memory（node-cache）做缓存，后面遇到对一致性要求比较强的需求(比如：抢购会启动几十到几百个实例，缺少一致性会影响到缓存效果)时，再改为redis（note : Redis cache is an external cache and is not reset when redeploy application）</p>\n<h2>性能测试</h2>\n<p>autocannon -c 100 -d 5 -p 1 http://127.0.0.1:3000/</p>\n<h3>压测</h3>\n<p>ab -c 10 -n 1000 http://localhost:3000/en-US/\nor \nautocannon -c 10 -a 1000 http://localhost:3000/en-US/\ncombined with</p>\n<h3>内存泄露分析基本步骤</h3>\n<ol start="0">\n<li>添加 require(\'heapdump\') 到 server/index.ts</li>\n<li>npm run build</li>\n<li>npm run start</li>\n<li>lsof -i:3000</li>\n<li>kill -USR2 <pid>（第三步查看到的pid）</li>\n<li>根据情况调整压测参数 autocannon -c 10 -a 10 http://localhost:3000/en-US/</li>\n<li>重复执行3次步骤 4，5</li>\n<li>浏览器打开控制台memory栏目，按照生成顺序载入生产的内存快照  heapdump开头的文件</li>\n</ol>\n<h3>复杂内存node分析基本步骤（主要是增加了访问量，以及线上环境模拟）</h3>\n<p>改变 autocannon 参数： autocannon -c 10 -d 60 http://localhost:3000/en-US/\n其它同上</p>\n<p>Todos:</p>\n<ol>\n<li>需要增加更丰富的线上环境模拟</li>\n</ol>\n'},{name:"sourceMap",value:'<h2>什么是 source-map?</h2>\n<h3>广义解释：</h3>\n<p>溯源</p>\n<h3>前端开发</h3>\n<p>“A source map provides a way of mapping code within a compressed file back to it’s original position in a source file”</p>\n<h5>V3 spec example:</h5>\n<pre><code class="language-json">{\n    version : 3,\n    file: &quot;out.js&quot;,\n    sourceRoot : &quot;&quot;,\n    sources: [&quot;foo.js&quot;, &quot;bar.js&quot;],\n    names: [&quot;src&quot;, &quot;maps&quot;, &quot;are&quot;, &quot;fun&quot;],\n    mappings: &quot;AAgBC,SAAQ,CAAEA&quot;\n}\n</code></pre>\n<h2>为什么使用 source-map?(debug)</h2>\n<p>前端模块打包发布基本流程：</p>\n<p>Modules -&gt; compilers -&gt; assets</p>\n<p>代码转换类型：</p>\n<ul>\n<li>编译（TypeScript)</li>\n<li>转译（Babel）</li>\n<li>压缩混淆（UglifyJS）</li>\n<li>合并多个文件，减少带宽请求。(Webpack, Rollup)</li>\n</ul>\n<ol>\n<li>dev 环境如何定位调试？</li>\n<li>产线出错如何定位调试？</li>\n</ol>\n<h2>source-map 如何映射</h2>\n<p>mappings: &quot;输出文件列位置|输入文件名|输入文件行号|输入文件列号,.....&quot;</p>\n<h3>优化措施：</h3>\n<ul>\n<li>文件名提取</li>\n<li>可符号化字符的提取</li>\n<li>记录相对位置</li>\n<li>VLQ编码</li>\n</ul>\n<p><a href="https://juejin.im/post/6844903869928079373">详细参考</a></p>\n<h2>souce-map 生成基本步骤</h2>\n<ol>\n<li>\n<p>Transform code and note the new generated source location</p>\n</li>\n<li>\n<p>Check for a difference in location between the original and generated code</p>\n</li>\n<li>\n<p>Using these mapping build a source map</p>\n</li>\n</ol>\n<p><a href="https://indepth.dev/source-maps-from-top-to-bottom/">具体参照这里</a></p>\n<h2>source-map 映射可视化</h2>\n<p><a href="https://sokra.github.io/source-map-visualization/#sass">online source-map visualization</a></p>\n<h2>source-map test case 写法</h2>\n<p><a href="https://github.com/wizardpisces/tiny-sass-compiler/blob/master/src/__tests__/compile.spec.ts">一种写法</a></p>\n<h2>参考资料</h2>\n<ol>\n<li>https://indepth.dev/source-maps-from-top-to-bottom/</li>\n<li>https://juejin.im/post/6844903869928079373</li>\n<li>https://www.npmjs.com/package/source-map</li>\n<li>https://www.html5rocks.com/en/tutorials/developertools/sourcemaps/</li>\n</ol>\n'},{name:"vueSSR",value:'<h1>Vue SSR</h1>\n<h2>vue ssr hydrate 原理</h2>\n<p>基本猜想：</p>\n<ol>\n<li>按照层级匹配，只在不匹配的时候报错，层次正确即可</li>\n<li>只在data-server-rendered=&quot;true&quot;的时候hydrate，随后移除data-server-rendered\nserver.html</li>\n</ol>\n<pre><code class="language-html"><span class="hljs-tag">&lt;<span class="hljs-name">div</span>&gt;</span><span class="hljs-tag">&lt;<span class="hljs-name">button</span>&gt;</span><span class="hljs-tag">&lt;<span class="hljs-name">a</span>&gt;</span><span class="hljs-tag">&lt;/<span class="hljs-name">a</span>&gt;</span><span class="hljs-tag">&lt;/<span class="hljs-name">button</span>&gt;</span><span class="hljs-tag">&lt;/<span class="hljs-name">div</span>&gt;</span>\n</code></pre>\n<p>will match client</p>\n<pre><code class="language-html"><span class="hljs-tag">&lt;<span class="hljs-name">div</span>&gt;</span><span class="hljs-tag">&lt;/<span class="hljs-name">div</span>&gt;</span>\n</code></pre>\n<p>but not match client</p>\n<pre><code class="language-html"><span class="hljs-tag">&lt;<span class="hljs-name">div</span>&gt;</span><span class="hljs-tag">&lt;<span class="hljs-name">a</span>&gt;</span><span class="hljs-tag">&lt;/<span class="hljs-name">a</span>&gt;</span><span class="hljs-tag">&lt;/<span class="hljs-name">div</span>&gt;</span>\n</code></pre>\n<h3>vue-lazy-hydrate原理</h3>\n<ul>\n<li>服务端：</li>\n</ul>\n<ol>\n<li>hydrate=true -&gt; 渲染出来的正常待hydrate的 html 占位</li>\n</ol>\n<ul>\n<li>客户端：</li>\n</ul>\n<ol>\n<li>最初hydrate=false 渲染最外层标签，刚好满足hydrate成功 -&gt; 直接渲染原来服务端输出的html</li>\n<li>在 visible | idle 等条件触发时修改 hydrate=true -&gt; 触发 render -&gt; 根据 hydrate=true 输出正常组件替换原来位置</li>\n</ol>\n<h3>vue-no-ssr原理</h3>\n<ul>\n<li>服务端：</li>\n</ul>\n<p>1. h(false) 占位</p>\n<ul>\n<li>客户端：</li>\n</ul>\n<p>1. 根据parent._isMounted 返回正常组件替换</p>\n<h2>SSR runInNewContext</h2>\n<h3>in NuxtJs</h3>\n<ul>\n<li>in dev : true(代表plugin middleware等文件会在每个请求进入的时候重新载入)</li>\n<li>in production: false （代表不会重新载入plugin，只会反复执行返回的函数）</li>\n</ul>\n<h3>vue SSR code structure (删除了很多代码，只保留了基本骨架)</h3>\n<ol>\n<li>bundle code</li>\n</ol>\n<pre><code class="language-js">\n<span class="hljs-function"><span class="hljs-keyword">function</span> <span class="hljs-title">compileModule</span> (<span class="hljs-params">files, basedir, runInNewContext</span>) </span>{\n  <span class="hljs-function"><span class="hljs-keyword">function</span> <span class="hljs-title">getCompiledScript</span> (<span class="hljs-params">filename</span>) </span>{\n    <span class="hljs-keyword">var</span> code = files[filename];\n\n    <span class="hljs-comment">// wrap code so each time run code will load dependencies which means run in new context</span>\n    <span class="hljs-keyword">var</span> wrapper = NativeModule.wrap(code);\n\n    <span class="hljs-keyword">var</span> script = <span class="hljs-keyword">new</span> vm.Script(wrapper, {\n      <span class="hljs-attr">filename</span>: filename,\n      <span class="hljs-attr">displayErrors</span>: <span class="hljs-literal">true</span>\n    });\n    <span class="hljs-keyword">return</span> script\n  }\n\n  <span class="hljs-function"><span class="hljs-keyword">function</span> <span class="hljs-title">evaluateModule</span> (<span class="hljs-params">filename, sandbox, evaluatedFiles</span>) </span>{\n    <span class="hljs-keyword">var</span> script = getCompiledScript(filename);\n    <span class="hljs-keyword">var</span> compiledWrapper = runInNewContext === <span class="hljs-literal">false</span>\n      ? script.runInThisContext()\n      : script.runInNewContext(sandbox);\n    <span class="hljs-keyword">var</span> m = { <span class="hljs-attr">exports</span>: {}};\n\n    <span class="hljs-comment">// rewrite require to load file in new context</span>\n    <span class="hljs-keyword">var</span> r = <span class="hljs-function"><span class="hljs-keyword">function</span> (<span class="hljs-params">file</span>) </span>{\n      <span class="hljs-keyword">if</span> (files[file]) {\n        <span class="hljs-keyword">return</span> evaluateModule(file, sandbox, evaluatedFiles)\n      }<span class="hljs-keyword">else</span> {\n        <span class="hljs-keyword">return</span> <span class="hljs-built_in">require</span>(file)\n      }\n    };\n    compiledWrapper.call(m.exports, m.exports, r, m);\n\n    <span class="hljs-keyword">var</span> res = <span class="hljs-built_in">Object</span>.prototype.hasOwnProperty.call(m.exports, <span class="hljs-string">&#x27;default&#x27;</span>)\n      ? m.exports.default\n      : m.exports;\n    <span class="hljs-keyword">return</span> res\n  }\n  <span class="hljs-keyword">return</span> evaluateModule\n}\n\n<span class="hljs-function"><span class="hljs-keyword">function</span> <span class="hljs-title">createBundleRunner</span> (<span class="hljs-params">entry, files, basedir, runInNewContext</span>) </span>{\n    <span class="hljs-keyword">var</span> evaluate = compileModule(files, basedir, runInNewContext)\n\n\n    <span class="hljs-keyword">if</span> (runInNewContext !== <span class="hljs-literal">false</span> &amp;&amp; runInNewContext !== <span class="hljs-string">&#x27;once&#x27;</span>) {\n        <span class="hljs-keyword">return</span> <span class="hljs-function"><span class="hljs-keyword">function</span> (<span class="hljs-params">userContext</span>) </span>{\n            <span class="hljs-keyword">return</span> <span class="hljs-keyword">new</span> <span class="hljs-built_in">Promise</span>(<span class="hljs-function"><span class="hljs-keyword">function</span> (<span class="hljs-params">resolve</span>) </span>{\n                <span class="hljs-keyword">var</span> res = evaluate(entry, createSandbox(userContext));\n                resolve(<span class="hljs-keyword">typeof</span> res === <span class="hljs-string">&#x27;function&#x27;</span> ? res(userContext) : res);\n            });\n        }\n    }<span class="hljs-keyword">else</span>{\n        <span class="hljs-keyword">var</span> runner; \n        <span class="hljs-comment">//cache runner so do not nead to load file when runInNewContext is false or once in production which has better performance than runInNewContext=true</span>\n        <span class="hljs-keyword">return</span> <span class="hljs-function"><span class="hljs-keyword">function</span> (<span class="hljs-params">userContext</span>) </span>{\n            <span class="hljs-keyword">return</span> <span class="hljs-keyword">new</span> <span class="hljs-built_in">Promise</span>(<span class="hljs-function"><span class="hljs-keyword">function</span> (<span class="hljs-params">resolve</span>) </span>{\n                <span class="hljs-keyword">if</span> (!runner) {\n                  runner = evaluate(entry, sandbox);\n                }\n                resolve(runner(userContext));\n            })\n        }\n    }\n}\n\n<span class="hljs-function"><span class="hljs-keyword">function</span> <span class="hljs-title">createBundleRenderer</span> (<span class="hljs-params">\n    bundle, <span class="hljs-regexp">//</span>(used webpack generated server manifest object)\n    rendererOptions\n  </span>)</span>{\n    <span class="hljs-keyword">let</span> run = createBundleRunner(entry,files,basedir,rendererOptions.runInNewContext) \n    <span class="hljs-keyword">return</span> {\n        renderToString(context){\n            run(context).then()\n        },\n        renderToStream(context){\n            run(context).then()\n        }\n    }\n\n  }\n</code></pre>\n<h3>reference</h3>\n<ul>\n<li><a href="https://nodejs.org/api/vm.html">node vm</a></li>\n<li><a href="https://nodejs.org/api/modules.html#modules_the_module_wrapper">node module</a></li>\n<li><a href="https://segmentfault.com/a/1190000008587112">node require解析</a></li>\n<li><a href="https://harttle.land/2020/02/10/deep-into-vue-ssr.html">vue ssr in depth</a></li>\n<li><a href="https://zhuanlan.zhihu.com/p/61348429">vue ssr in depth2</a></li>\n</ul>\n'}],i={name:"BlogVueSSr",setup:()=>({activeBlog:n("nuxt"),blogs:r})},c={class:"blog"},h={class:"left"};i.render=function(n,r,i,u,d,m){const j=s("klk-tab-panel"),w=s("klk-tabs");return a(),e("div",c,[l("div",h,[l(w,{modelValue:u.activeBlog,"onUpdate:modelValue":r[1]||(r[1]=n=>u.activeBlog=n),"tab-position":"left"},{default:p((()=>[(a(!0),e(t,null,o(u.blogs,(n=>(a(),e(j,{key:n.name,name:n.name},{default:p((()=>[l("p",{style:{margin:"0"},innerHTML:n.value},null,8,["innerHTML"])])),_:2},1032,["name"])))),128))])),_:1},8,["modelValue"])])])};export default i;export{r as blogs};
